const { sendError } = require('../../lib/errors');

function updateTask(project, taskId, status) {
  const task = project.tasks.find(task => task.id === taskId);
  if (!task) {
    return sendError(null, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  if (status !== 'todo' && status !== 'done') {
    return sendError(null, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  task.status = status;
  return project;
}

module.exports = {
  updateTask
};
